@namespace Lumeo
@implements IAsyncDisposable

<div id="@_elementId" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@inject IComponentInteropService Interop

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int OffsetTop { get; set; } = 0;
    [Parameter] public int? OffsetBottom { get; set; }
    [Parameter] public string? Target { get; set; }
    [Parameter] public EventCallback<bool> OnChange { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _elementId = LumeoIds.New("affix");
    private bool _registered;
    private bool _isFixed;
    private bool _disposed;

    // The JS registerAffix closure captures offsetTop/offsetBottom/targetSelector
    // by value, so the only way to honour a runtime change to any of them is to
    // tear the registration down and re-create it. Remember the tuple we last
    // registered with so OnAfterRenderAsync can detect a change and re-register
    // instead of latching on the first render forever.
    private (int OffsetTop, int? OffsetBottom, string? Target) _appliedConfig;

    private string CssClass => Class ?? "";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_disposed) return;

        var config = (OffsetTop, OffsetBottom, Target);

        if (!_registered)
        {
            await RegisterAsync(config);
            return;
        }

        // Already registered: re-register only when the consumer changed an offset
        // or the scroll target after the first render (the JS closure can't see the
        // new values otherwise).
        if (!_appliedConfig.Equals(config))
        {
            try { await Interop.UnregisterAffix(_elementId); }
            catch (JSDisconnectedException) { }
            catch (ObjectDisposedException) { }

            // Drop the stale edge-trigger state: the new registration starts from a
            // clean "not fixed" baseline so the first OnChange reflects the real
            // stick/unstick boundary under the new config rather than a latched flag.
            _isFixed = false;
            _registered = false;
            await RegisterAsync(config);
        }
    }

    private async Task RegisterAsync((int OffsetTop, int? OffsetBottom, string? Target) config)
    {
        try
        {
            await Interop.RegisterAffix(_elementId, config.OffsetTop, config.OffsetBottom, config.Target, async (isFixed) =>
            {
                // The JS watcher may fire one more time between dispose and teardown;
                // don't touch a torn-down component (avoids ObjectDisposedException).
                if (_disposed) return;
                if (_isFixed != isFixed)
                {
                    _isFixed = isFixed;
                    await OnChange.InvokeAsync(isFixed);
                    await InvokeAsync(StateHasChanged);
                }
            });

            // Disposal can land while the registration above is still in flight: the
            // JS side has already attached its scroll/resize listeners and the
            // affixHandlers Map entry, but DisposeAsync ran before _registered was set
            // and so skipped teardown. Detect that here and unregister immediately so
            // the listeners + Map entry don't leak.
            if (_disposed)
            {
                try { await Interop.UnregisterAffix(_elementId); }
                catch (JSDisconnectedException) { }
                catch (ObjectDisposedException) { }
                return;
            }

            _registered = true;
            _appliedConfig = config;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_disposed) return;
        _disposed = true;

        // Teardown is unconditional, not gated on _registered: a dispose that lands
        // mid-registration (before _registered is set, but after JS already wired the
        // scroll/resize listeners) must still tear down. UnregisterAffix is a safe
        // no-op for an unknown id (JS unregisterAffix guards on `if (handler)`), so an
        // unregistered or never-fully-registered instance won't throw.
        try { await Interop.UnregisterAffix(_elementId); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
    }
}
